import { lazy, Suspense } from 'react'
import { createBrowserRouter, RouterProvider, Navigate } from 'react-router-dom'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import { ReactQueryDevtools } from '@tanstack/react-query-devtools'
import { ThemeProvider } from '@/context/ThemeContext'
import { AppLayout } from '@/routes/_layout'
import { IndexRoute } from '@/routes/index'
// GraphRoute is lazy-loaded so the Cosmograph WebGL bundle (~500 KB gzipped)
// is only fetched when the user navigates to /graph/*.  All other surfaces
// load instantly without pulling in the GPU renderer. (#1249 perf)
const GraphRoute = lazy(() =>
  import('@/routes/graph').then((m) => ({ default: m.GraphRoute })),
)
import { FlowsRoute } from '@/routes/flows'
import { TopologyRoute } from '@/routes/topology'
import { PathsRoute } from '@/routes/paths'
import { PathsDetailRoute } from '@/routes/paths.detail'
import { DocsRoute } from '@/routes/docs'
import { PendingRoute } from '@/routes/pending'
import { DiagnosticsRoute } from '@/routes/diagnostics'
import { PatternsRoute } from '@/routes/patterns'
import { SystemRoute } from '@/routes/system'
import { UpdateRoute } from '@/routes/update'
import { SettingsRoute } from '@/routes/settings'
import { QualityRoute } from '@/routes/quality'
import { SecurityRoute } from '@/routes/security'
import { MCPActivityRoute } from '@/routes/mcp-activity'
import { AuditLogRoute } from '@/routes/audit-log'
import { OnboardRoute } from '@/routes/onboard'
import { MCPSetupRoute } from '@/routes/mcp-setup'
import { HelpRoute } from '@/routes/help'
import SkillsPage from '@/routes/skills'
import { RouterErrorBoundary } from '@/components/RouterErrorBoundary'
import { EmptyState } from '@/components/shared/EmptyState'
import { Globe } from 'lucide-react'

// Fallback shown while the Cosmograph chunk downloads on first visit to /graph/*.
function GraphLoadingFallback() {
  return (
    <div className="flex h-full items-center justify-center text-slate-500 dark:text-slate-400 text-sm">
      Loading graph renderer…
    </div>
  )
}

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: 2,
      staleTime: 30 * 1000,
      gcTime: 5 * 60 * 1000,
    },
  },
})

const router = createBrowserRouter([
  {
    path: '/',
    element: <AppLayout />,
    errorElement: <RouterErrorBoundary />,
    children: [
      { index: true, element: <IndexRoute /> },

      // Surface 1 — Graph (lazy — Cosmograph chunk only loads on first visit)
      { path: 'graph', element: <Navigate to="/graph/fixture-a" replace /> },
      {
        path: 'graph/:group',
        element: (
          <Suspense fallback={<GraphLoadingFallback />}>
            <GraphRoute />
          </Suspense>
        ),
      },

      // Surface 2 — Flows
      { path: 'flows', element: <Navigate to="/flows/fixture-a" replace /> },
      { path: 'flows/:group', element: <FlowsRoute /> },

      // Surface 3 — Topology
      { path: 'topology', element: <Navigate to="/topology/fixture-a" replace /> },
      { path: 'topology/:group', element: <TopologyRoute /> },

      // Surface 4 — API Explorer (with nested detail route)
      { path: 'paths', element: <Navigate to="/paths/fixture-a" replace /> },
      {
        path: 'paths/:group',
        element: <PathsRoute />,
        children: [
          {
            index: true,
            element: (
              <div className="h-full flex items-center justify-center text-slate-500 dark:text-slate-600">
                <EmptyState
                  icon={Globe}
                  title="Select a path"
                  message="Click any path in the list to view its handlers, response shapes, and dependencies."
                />
              </div>
            ),
          },
          { path: ':pathHash', element: <PathsDetailRoute /> },
        ],
      },

      // Surface 5 — Docs
      { path: 'docs', element: <Navigate to="/docs/fixture-a" replace /> },
      { path: 'docs/:group', element: <DocsRoute /> },
      { path: 'docs/:group/*', element: <DocsRoute /> },

      // Surface 6 — Pending queue (repairs + enrichments, #987)
      { path: 'pending', element: <Navigate to="/pending/fixture-a" replace /> },
      { path: 'pending/:group', element: <PendingRoute /> },

      // Surface 7 — Diagnostics (#1187)
      { path: 'diagnostics', element: <DiagnosticsRoute /> },

      // Surface 8 — Patterns (#1189)
      { path: 'patterns', element: <Navigate to="/patterns/fixture-a" replace /> },
      { path: 'patterns/:group', element: <PatternsRoute /> },

      // Surface 9 — System / daemon control panel (#1195)
      { path: 'system', element: <SystemRoute /> },

      // Surface 10 — Update / Version management (#1199)
      { path: 'update', element: <UpdateRoute /> },

      // Surface 11 — Quality / health-score history (#1198, #1214)
      { path: 'quality', element: <Navigate to="/quality/fixture-a" replace /> },
      { path: 'quality/:group', element: <QualityRoute /> },

      // Surface 17 — Security & Quality findings (#1330)
      { path: 'security', element: <Navigate to="/security/fixture-a" replace /> },
      { path: 'security/:group', element: <SecurityRoute /> },

      // Surface 12 — Settings (#1206)
      { path: 'settings', element: <SettingsRoute /> },

      // Surface 12 — MCP Activity Log (#1226)
      { path: 'mcp-activity', element: <MCPActivityRoute /> },

      // Surface 13 — Web onboarding wizard (#1239)
      { path: 'onboard', element: <OnboardRoute /> },

      // Surface 14 — Audit Log (#1258)
      { path: 'audit-log', element: <AuditLogRoute /> },

      // Surface 15 — MCP Setup Wizard (#1247)
      { path: 'mcp-setup', element: <MCPSetupRoute /> },

      // Surface 16 — Help & About (#1253)
      { path: 'help', element: <HelpRoute /> },

      // Surface 18 — Skills surface (#1354)
      { path: 'skills', element: <SkillsPage /> },
    ],
  },
])

export function App() {
  return (
    <ThemeProvider>
      <QueryClientProvider client={queryClient}>
        <RouterProvider router={router} />
        {import.meta.env.DEV && <ReactQueryDevtools initialIsOpen={false} />}
      </QueryClientProvider>
    </ThemeProvider>
  )
}
